// // This module implements a four-input, one-bit wide demultiplexer with disable functionality. The output (out) is only active when the enable signal (en) is low, and it selects one of the four inputs (in0, in1, in2, in3) based on the two-bit select signal (sel).
module top_module(
  input in0,
  input in1,
  input in2,
  input in3,
  input [1:0] sel,
  input en,
  output reg out  // Changed from wire to reg
);always @(*) begin
    if (en) begin
      case (sel)
        2'b00: out = in0;
        2'b01: out = in1;
        2'b10: out = in2;
        2'b11: out = in3;
        default: out = 1'b0; // Added default case for safety
      endcase
    end else begin
      out = 1'b0;
    end
  end

endmodule
